    map['message'] = message;
    map['totalExercises'] = totalExercises;
    map['totalPages'] = totalPages;
    map['currentPage'] = currentPage;
    if (exercises != null) {
      map['exercises'] = exercises?.map((v) => v.toJson()).toList();
    }
    return map;
  }

